package main.rice.concisegen;

import main.rice.test.TestCase;
import main.rice.test.TestResults;
import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

/**
 * A class for generating a minimal (concise) set of test cases that still catches all
 * buggy implementations, using a greedy set cover algorithm.
 */
public class ConciseSetGenerator {

    /**
     * Returns a minimal set of test cases from results that together cover all buggy
     * implementations (i.e., every implementation in wrongSet is caught by at least one
     * chosen test case).
     *
     * Uses a greedy approach: at each step, choose the test case that covers the most
     * still-uncovered buggy implementations.
     *
     * Does NOT mutate the input TestResults object.
     *
     * @param results the results of running all test cases on all implementations
     * @return a minimal list of test cases covering all buggy implementations
     */
    public static List<TestCase> setCover(TestResults results) {
        List<Set<Integer>> caseToFiles = results.getCaseToFiles();
        Set<Integer> wrongSet = results.getWrongSet();

        // Work on a copy of wrongSet so we don't mutate the original
        Set<Integer> remaining = new HashSet<>(wrongSet);

        List<TestCase> chosen = new ArrayList<>();

        while (!remaining.isEmpty()) {
            int bestIndex = -1;
            int bestCount = 0;

            // Find the test case covering the most remaining buggy files
            for (int i = 0; i < caseToFiles.size(); i++) {
                // Count intersection with remaining (without mutating caseToFiles sets)
                int count = 0;
                for (Integer fileIdx : caseToFiles.get(i)) {
                    if (remaining.contains(fileIdx)) {
                        count++;
                    }
                }
                if (count > bestCount) {
                    bestCount = count;
                    bestIndex = i;
                }
            }

            // If no test covers any remaining file, we can't do better — stop
            if (bestIndex == -1 || bestCount == 0) {
                break;
            }

            // Add the best test case to our result
            chosen.add(results.getTestCase(bestIndex));

            // Remove all files this test case covers from remaining
            remaining.removeAll(caseToFiles.get(bestIndex));
        }

        return chosen;
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyFloatObj;
import java.util.ArrayList;
import java.util.List;

/**
 * A node that generates PyFloatObj values from a double domain.
 */
public class PyFloatNode extends APyNode<Double> {

    /**
     * Returns null, since PyFloatNode is a leaf node with no children.
     *
     * @return null
     */
    @Override
    public APyNode<?> getLeftChild() {
        return null;
    }

    /**
     * Returns null, since PyFloatNode is a leaf node with no children.
     *
     * @return null
     */
    @Override
    public APyNode<?> getRightChild() {
        return null;
    }

    /**
     * Generates all PyFloatObj values corresponding to the exhaustive domain.
     *
     * @return a list of PyFloatObj values for each value in the exhaustive domain
     */
    @Override
    public List<APyObj> genExVals() {
        List<APyObj> vals = new ArrayList<>();
        for (Double domainVal : this.getExDomain()) {
            vals.add(new PyFloatObj(domainVal));
        }
        return vals;
    }

    /**
     * Generates a single random PyFloatObj from the random domain.
     *
     * @return a randomly chosen PyFloatObj
     */
    @Override
    public APyObj genRandVal() {
        List<Double> ranDomain = this.getRanDomain();
        int idx = rand.nextInt(ranDomain.size());
        return new PyFloatObj(ranDomain.get(idx));
    }
}

