package main.rice.node;

import main.rice.obj.APyObj;
import java.util.List;
import java.util.Random;

/**
 * An abstract class representing a node that can generate Python objects of a
 * specific type, given an exhaustive and a random domain.
 *
 * @param <T> the type of values in the domain (e.g., Integer for bool/int, Double for float)
 */
public abstract class APyNode<T extends Number> {

    /** The exhaustive domain: values used during exhaustive test generation. */
    private List<T> exDomain;

    /** The random domain: values used during random test generation. */
    private List<T> ranDomain;

    /** Shared random number generator for random value generation. */
    protected static final Random rand = new Random();

    /**
     * Sets the exhaustive domain.
     *
     * @param exDomain the list of values for exhaustive generation
     */
    public void setExDomain(List<T> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Returns the exhaustive domain.
     *
     * @return the exhaustive domain
     */
    public List<T> getExDomain() {
        return this.exDomain;
    }

    /**
     * Sets the random domain.
     *
     * @param ranDomain the list of values for random generation
     */
    public void setRanDomain(List<T> ranDomain) {
        this.ranDomain = ranDomain;
    }

    /**
     * Returns the random domain.
     *
     * @return the random domain
     */
    public List<T> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Returns the left child of this node, or null if this is a leaf node.
     *
     * @return the left child, or null
     */
    public abstract APyNode<?> getLeftChild();

    /**
     * Returns the right child of this node, or null if this is a leaf node.
     *
     * @return the right child, or null
     */
    public abstract APyNode<?> getRightChild();

    /**
     * Generates all Python objects corresponding to values in the exhaustive domain.
     *
     * @return a list of all PyObj values from the exhaustive domain
     */
    public abstract List<APyObj> genExVals();

    /**
     * Generates a single random Python object chosen from the random domain.
     *
     * @return a randomly chosen PyObj from the random domain
     */
    public abstract APyObj genRandVal();
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyBoolObj;
import java.util.ArrayList;
import java.util.List;

/**
 * A node that generates PyBoolObj values.
 * Domain values: 0 represents false, 1 represents true.
 */
public class PyBoolNode extends APyNode<Integer> {

    /**
     * Returns null, since PyBoolNode is a leaf node with no children.
     *
     * @return null
     */
    @Override
    public APyNode<?> getLeftChild() {
        return null;
    }

    /**
     * Returns null, since PyBoolNode is a leaf node with no children.
     *
     * @return null
     */
    @Override
    public APyNode<?> getRightChild() {
        return null;
    }

    /**
     * Generates all PyBoolObj values corresponding to the exhaustive domain.
     * Domain value 0 maps to false; 1 maps to true.
     *
     * @return a list of PyBoolObj values for each value in the exhaustive domain
     */
    @Override
    public List<APyObj> genExVals() {
        List<APyObj> vals = new ArrayList<>();
        for (Integer domainVal : this.getExDomain()) {
            vals.add(new PyBoolObj(domainVal == 1));
        }
        return vals;
    }

    /**
     * Generates a single random PyBoolObj from the random domain.
     *
     * @return a randomly chosen PyBoolObj
     */
    @Override
    public APyObj genRandVal() {
        List<Integer> ranDomain = this.getRanDomain();
        int idx = rand.nextInt(ranDomain.size());
        return new PyBoolObj(ranDomain.get(idx) == 1);
    }
}

